<template>
  <div class="hello">
    <el-container>
      <el-header class="el-header">
        <h3>书籍📚信息</h3>
        <h6 style="text-align: right;margin-right: 50px">Collect By:nixs</h6>
      </el-header>
      <el-main>
        <div class="timeline">
          <el-collapse @change="handleChange">
            <div class="books"
                 v-for="item in books"
                 :key="item.id">
              <el-collapse-item :title="item.title">
                <div>
                  <el-avatar :src="item.cover" size="100"></el-avatar>
                </div>
                <div class="itemabs">{{item.abs}}</div>
                <div class="itemtime">{{item.date.toLocaleString()}}</div>
              </el-collapse-item>
            </div>
          </el-collapse>
        </div>
      </el-main>
      <el-footer class="el-footer">
        <div class="mineinfo">
          <el-carousel :interval="4000" type="card" height="200px">
            <el-carousel-item v-for="item in mineinfo" :key="item">
              <el-tag effect="dark" style="color: black;font-weight: bold;font-size: large">{{ item }}</el-tag>
            </el-carousel-item>
          </el-carousel>
        </div>
      </el-footer>
    </el-container>
  </div>
</template>

<script>
export default {
  name: 'HelloWorld',
  // 数据提供
  data: function () {
    return {
      msg: 'Welcome to Your Vue.js App.(nixinsheng)' + new Date().toLocaleString(),
      author: '倪新生',
      work_address: 'BeiJing.CHINA',
      email: '1911398892@qq.com',
      reverse: true,
      books: [],
      mineinfo: [
        {author: '倪新生'},
        {email: '1911398892@qq.com'},
        {skill: 'iOS/Android/Java'},
        {address: 'BeiJing*CHINA'}
      ]
    }
  },
  mounted: function () {
    console.log('进入就调用加载书籍信息函数loadBooks')
    this.loadBooks()
  },
  methods: {
    loadBooks () {
      console.log('get-loadBooks')
      var _this = this
      this.$axios.get('/books').then(resp => {
        if (resp && resp.status === 200) {
          console.log('接口请求数据结果：' + resp.data.length + resp.data[0].title)
          _this.books = resp.data
        }
      })
    },
    handleChange (val) {
      console.log(val)
    }
  }
}
</script>

<!-- Add "scoped" attribute to limit CSS to this component only -->
<style scoped>
  h1, h2 {
    font-weight: bold;
  }

  ul {
    list-style-type: none;
    padding: 0;
  }

  li {
    display: inline-block;
    margin: 0 10px;
  }

  a {
    color: #42b98F;
  }
  .timeline {
    border-radius: 15px;
    background-clip: padding-box;
    margin: 50px auto 90px;
    width: 90%;
    padding: 35px 35px 15px 35px;
    background: #fff;
    border: 1px solid #eaeaea;
    box-shadow: 0 0 25px #cac6c6;
  }
  .itemabs {
    padding: auto 20px;
    text-align: left;
  }
  .itemtime {
    padding: auto auto 20px;
    text-align: right;
  }
  .mineinfo {
    border-radius: 15px;
    background-clip: padding-box;
    margin: 10px auto;
    width: 90%;
    height: 50px;
    padding: 35px 35px 15px 35px;
    background: #fff;
    border: 1px solid #eaeaea;
    box-shadow: 0 0 25px #cac6c6;
  }
  /*.el-header, .el-footer {*/
  .el-header {
    background-color: #B3C0D1;
    color: #333;
    text-align: center;
    line-height: 60px;
  }
  .el-footer {
    background-color: #fff;
    color: #333;
    text-align: center;
  }
</style>



